using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the trainer as a singleton so label metadata survives across requests.
builder.Services.AddSingleton<TicketModelTrainer>();

var app = builder.Build();

// Train the model at startup and register the PredictionEnginePool with the saved model.
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
var modelPath = trainer.TrainAndEvaluate();

builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

// Rebuild the service provider so the pool is available to controllers.
// Instead, register the pool before building. We need to restructure slightly.
app.MapControllers();
app.Run();

